import React from 'react';

/**
 * A reusable button component with TypeScript typing
 * @param {Object} props
 * @param {React.ReactNode} props.children - Button content
 * @param {Function} props.onClick - Click handler
 */
const PrimaryActionButton: React.FC<{ children: React.ReactNode; onClick?: () => void }> = ({ children, onClick = () => {} }) => {
  return (
    <button
      onClick={onClick}
      className="bg-blue-500 text-white px-4 py-2 rounded"
      type="button"
    >
      {children}
    </button>
  );
};

export default PrimaryActionButton;

